-- releases
CREATE TABLE IF NOT EXISTS `plfs.releases` (
  release_id STRING NOT NULL,
  label STRING NOT NULL,
  format STRING NOT NULL  OPTIONS(description='\'annual\' or \'calendar\'.'),
  year_label STRING NOT NULL,
  period_start STRING NOT NULL  OPTIONS(description='First month of reference period.'),
  period_end STRING NOT NULL  OPTIONS(description='Last month of reference period.'),
  catalog_id STRING NOT NULL,
  catalog_url STRING NOT NULL,
  weight_rule STRING NOT NULL  OPTIONS(description='\'combined\' / \'half_yearly\' / \'simple\' / \'limited\'. See WEIGHTS.md.'),
  input_kind STRING NOT NULL  OPTIONS(description='\'txt\' (fixed-width) / \'csv\' / \'tsv\' — source format.'),
  n_files INT64 NOT NULL,
  file_keys STRING NOT NULL  OPTIONS(description='Pipe-separated list (e.g., \'hhv1|hhrv|perv1|perrv\').')
);

